#include <stdio.h>
int main() {
    FILE *fp;
    fp = fopen("sample.txt", "w");

    if (fp == NULL) {
        printf("Error: Could not open file\n");
        return 1;
    }

    fprintf(fp, "Hello, World!\n");
    fprintf(fp, "Welcome to File Handling in C\n");

    fclose(fp);
    printf("File written successfully\n");
    return 0;
}

#include <stdio.h>
int main() {
    FILE *fp;
    int ch;

    fp = fopen("sample.txt", "r");

    if (fp == NULL) {
        printf("Error: Could not open file\n");
        return 1;
    }

    while ((ch = fgetc(fp)) != EOF) {
        putchar(ch);
    }

    if (ferror(fp)) {
        printf("\nError reading file\n");
    }

    fclose(fp);
    return 0;
}

#include <stdio.h>
int main() {
    FILE *fp;

    // Open in append mode - creates if doesn't exist
    fp = fopen("log.txt", "a");

    if (fp == NULL) {
        printf("Error: Could not open file\n");
        return 1;
    }

    // Append timestamp-like data
    fprintf(fp, "[INFO] Application started\n");
    fprintf(fp, "[INFO] User logged in\n");
    fprintf(fp, "[ERROR] Connection failed\n");

    fclose(fp);
    printf("Data appended successfully\n");
    return 0;
}
